import './Grid.scss';

import { Box } from ':components/Box';
import { classNames } from ':helpers/classnames';
import type { FC } from 'react';
import React from 'react';
import type { GridProps } from './Grid.types';

export const Grid: FC<GridProps> = ({
	as,
	columns = 1,
	gap = 'none',
	columnGap,
	rowGap,
	align = 'stretch',
	justify = 'stretch',
	className,
	dataTestId = 'Grid',
	...rest
}) => {
	const gridClassName = classNames(
		'dsb_grid',
		`dsb_grid__columns-${columns}`,
		gap && `dsb_grid__gap-${gap}`,
		columnGap && `dsb_grid__column-gap-${columnGap}`,
		rowGap && `dsb_grid__row-gap-${rowGap}`,
		align && `dsb_grid__align-${align}`,
		justify && `dsb_grid__justify-${justify}`,
		className,
	);

	return <Box as={as} display="grid" className={gridClassName} dataTestId={dataTestId} {...rest} />;
};

Grid.displayName = 'Grid';
